# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

package com.example.biometricauth

import android.content.Context
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import android.content.Intent
import android.view.View
import android.widget.LinearLayout
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    companion object {
        const val PREF_NAME = "biometric_auth_prefs"
        const val KEY_AUTHENTICATED = "is_authenticated"
        const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
        const val KEY_USERNAME = "saved_username"
        const val KEY_PASSWORD = "saved_password"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        sharedPreferences = getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)

        if (isAuthenticated()) {
            navigateToHome()
            return
        }

        setContentView(createLoginLayout())
        setupBiometricAuthentication()

        if (isBiometricAvailable() && isBiometricEnabled()) {
            showBiometricPrompt()
        }
    }

    private fun createLoginLayout(): View {
        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
        }

        val titleText = TextView(this).apply {
            text = "Welcome"
            textSize = 28f
            setPadding(0, 0, 0, 48)
        }
        layout.addView(titleText)

        val subtitleText = TextView(this).apply {
            text = "Sign in to continue"
            textSize = 16f
            setPadding(0, 0, 0, 32)
        }
        layout.addView(subtitleText)

        val usernameInput = EditText(this).apply {
            hint = "Username"
            id = View.generateViewId()
            tag = "username_input"
            setPadding(16, 16, 16, 16)
        }
        layout.addView(usernameInput)

        val passwordInput = EditText(this).apply {
            hint = "Password"
            id = View.generateViewId()
            tag = "password_input"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or
                    android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
            setPadding(16, 16, 16, 16)
        }
        layout.addView(passwordInput)

        val loginButton = Button(this).apply {
            text = "Login with Password"
            setOnClickListener {
                val username = usernameInput.text.toString().trim()
                val password = passwordInput.text.toString().trim()
                handlePasswordLogin(username, password)
            }
        }
        layout.addView(loginButton)

        val biometricButton = Button(this).apply {
            text = "Login with Fingerprint"
            setOnClickListener {
                if (isBiometricAvailable()) {
                    showBiometricPrompt()
                } else {
                    Toast.makeText(
                        this@MainActivity,
                        "Biometric authentication is not available on this device",
                        Toast.LENGTH_LONG
                    ).show()
                }
            }
        }

        if (isBiometricAvailable()) {
            layout.addView(biometricButton)
        }

        val statusText = TextView(this).apply {
            tag = "status_text"
            textSize = 14f
            setPadding(0, 24, 0, 0)
            setTextColor(ContextCompat.getColor(this@MainActivity, android.R.color.holo_red_dark))
        }
        layout.addView(statusText)

        return layout
    }

    private fun setupBiometricAuthentication() {
        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                            showStatusMessage("Please use password to login")
                        }
                        BiometricPrompt.ERROR_USER_CANCELED -> {
                            showStatusMessage("Authentication cancelled")
                        }
                        BiometricPrompt.ERROR_LOCKOUT -> {
                            showStatusMessage("Too many attempts. Please use password instead.")
                        }
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                            showStatusMessage("Biometric permanently locked. Use password to login.")
                        }
                        else -> {
                            showStatusMessage("Authentication error: $errString")
                        }
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onBiometricSuccess()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    showStatusMessage("Fingerprint not recognized. Try again or use password.")
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Use your fingerprint to sign in")
            .setDescription("Touch the fingerprint sensor to verify your identity")
            .setNegativeButtonText("Use Password Instead")
            .setConfirmationRequired(false)
            .build()
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> true
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                false
            }
            else -> false
        }
    }

    private fun isBiometricEnabled(): Boolean {
        return sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, true)
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun setAuthenticated(authenticated: Boolean) {
        sharedPreferences.edit().apply {
            putBoolean(KEY_AUTHENTICATED, authenticated)
            apply()
        }
    }

    private fun enableBiometric(enabled: Boolean) {
        sharedPreferences.edit().apply {
            putBoolean(KEY_BIOMETRIC_ENABLED, enabled)
            apply()
        }
    }

    private fun saveCredentials(username: String, password: String) {
        sharedPreferences.edit().apply {
            putString(KEY_USERNAME, username)
            putString(KEY_PASSWORD, password)
            apply()
        }
    }

    private fun handlePasswordLogin(username: String, password: String) {
        if (username.isEmpty() || password.isEmpty()) {
            showStatusMessage("Please enter both username and password")
            return
        }

        val savedUsername = sharedPreferences.getString(KEY_USERNAME, null)
        val savedPassword = sharedPreferences.getString(KEY_PASSWORD, null)

        if (savedUsername == null && savedPassword == null) {
            // First time login - save credentials
            saveCredentials(username, password)
            enableBiometric(true)
            onLoginSuccess()
        } else if (username == savedUsername && password == savedPassword) {
            onLoginSuccess()
        } else {
            showStatusMessage("Invalid username or password")
        }
    }

    private fun onBiometricSuccess() {
        Toast.makeText(this, "Biometric authentication successful!", Toast.LENGTH_SHORT).show()
        setAuthenticated(true)
        navigateToHome()
    }

    private fun onLoginSuccess() {
        Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()
        setAuthenticated(true)
        navigateToHome()
    }

    private fun navigateToHome() {
        val intent = Intent(this, HomeActivity::class.java)
        startActivity(intent)
        finish()
    }

    private fun showStatusMessage(message: String) {
        val rootView = findViewById<View>(android.R.id.content) as? android.view.ViewGroup
        rootView?.let { root ->
            findViewByTag<TextView>(root, "status_text")?.text = message
        }
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show()
    }

    @Suppress("UNCHECKED_CAST")
    private fun <T : View> findViewByTag(root: View, tag: String): T? {
        if (root.tag == tag) return root as? T
        if (root is android.view.ViewGroup) {
            for (i in 0 until root.childCount) {
                val found = findViewByTag<T>(root.getChildAt(i), tag)
                if (found != null) return found
            }
        }
        return null
    }
}

class HomeActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        sharedPreferences = getSharedPreferences(MainActivity.PREF_NAME, Context.MODE_PRIVATE)

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER_HORIZONTAL
        }

        val welcomeText = TextView(this).apply {
            text = "Welcome to Home Screen!"
            textSize = 24f
            setPadding(0, 0, 0, 16)
        }
        layout.addView(welcomeText)

        val authenticatedText = TextView(this).apply {
            text = "You are authenticated ✓"
            textSize = 18f
            setTextColor(ContextCompat.getColor(this@HomeActivity, android.R.color.holo_green_dark))
            setPadding(0, 0, 0, 16)
        }
        layout.addView(authenticatedText)

        val usernameText = TextView(this).apply {
            val savedUsername = sharedPreferences.getString(MainActivity.KEY_USERNAME, "User")
            text = "Hello, $savedUsername!"
            textSize = 20f
            setPadding(0, 0, 0, 48)
        }
        layout.addView(usernameText)

        val biometricStatusText = TextView(this).apply {
            val biometricEnabled = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, true)
            text = if (biometricEnabled) "Biometric Login: Enabled" else "Biometric Login: Disabled"
            textSize = 16f
            setPadding(0, 0, 0, 16)
        }
        layout.addView(biometricStatusText)

        val toggleBiometricButton = Button(this).apply {
            val biometricEnabled = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, true)
            text = if (biometricEnabled) "Disable Biometric Login" else "Enable Biometric Login"
            setOnClickListener {
                val currentState = sharedPreferences.getBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, true)
                val newState = !currentState
                sharedPreferences.edit().putBoolean(MainActivity.KEY_BIOMETRIC_ENABLED, newState).apply()
                this.text = if (newState) "Disable Biometric Login" else "Enable Biometric Login"
                biometricStatusText.text = if (newState) "Biometric Login: Enabled" else "Biometric Login: Disabled"
                Toast.makeText(
                    this@HomeActivity,
                    if (newState) "Biometric login enabled" else "Biometric login disabled",
                    Toast.LENGTH_SHORT
                ).show()
            }
        }
        layout.addView(toggleBiometricButton)

        val logoutButton = Button(this).apply {
            text = "Logout"
            setOnClickListener {
                logout()
            }
        }
        layout.addView(logoutButton)

        val clearDataButton = Button(this).apply {
            text = "Clear All Data & Logout"
            setOnClickListener {
                clearAllData()
            }
        }
        layout.addView(clearDataButton)

        setContentView(layout)
    }

    private fun logout() {
        sharedPreferences.edit().apply {
            putBoolean(MainActivity.KEY_AUTHENTICATED, false)
            apply()
        }
        Toast.makeText(this, "Logged out successfully", Toast.LENGTH_SHORT).show()
        navigateToLogin()
    }

    private fun clearAllData() {
        sharedPreferences.edit().clear().apply()
        Toast.makeText(this, "All data cleared", Toast.LENGTH_SHORT).show()
        navigateToLogin()
    }

    private fun navigateToLogin() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}